class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        forbidden = set()
        result = []
        num = 1

        while len(result) < n:
            valid = True
            for x in result:
                if x + num == k:
                    valid = False
                    break
            if valid:
                result.append(num)
                for x in result:
                    forbidden.add(x + num)
            num += 1

        return sum(result)
